const body = $input.first().json;
const eng    = body.engagement ?? {};
const output = body.output     ?? {};

return [{
  json: {
    clientName:    eng.clientName,
    company:       eng.company,
    serviceType:   eng.serviceType,
    owner:         eng.owner,
    documentType:  output.documentType,
    filename:      output.filename,
    generatedAt:   output.generatedAt,
    slackMessage:  `📄 Output ready: *${output.filename}*\n*Client:* ${eng.clientName} — ${eng.company}\n*Type:* ${output.documentType}\n*Owner:* ${eng.owner}`,
    emailSubject:  `Output ready: ${output.documentType} for ${eng.clientName}`,
    emailBody:     `A new output document has been generated in Barinhall Delivery Hub.\n\nClient: ${eng.clientName}\nCompany: ${eng.company}\nDocument type: ${output.documentType}\nFilename: ${output.filename}\nGenerated: ${output.generatedAt}`
  }
}];
